-- OPENSERP-SERVERLESS-STATE-PROD-MIGRATION-1
-- Single-paste Production application: both frozen migrations + the frozen
-- seed, one transaction. Additive only -- no DROP/TRUNCATE/DELETE, no
-- listing table touched. Auto-rolls-back on any verification mismatch.

begin;

-- OPENSERP-SERVERLESS-STATE-PERSISTENCE-1
-- Objective: replace the local-filesystem rewrite of data/openserp/query-universe-v1.json
--   (which crashes with EROFS on Vercel's read-only serverless filesystem) with a
--   PostgreSQL table holding the mutable rotation state per query. The JSON file
--   itself stays as an immutable, versioned static catalog (query_definition only).
-- Preconditions: none (fresh, additive table).
-- Impact: creates 1 new table + indexes. No existing table touched. No PII, no raw
--   SERP data, no listing URLs stored here -- only rotation bookkeeping keyed by
--   query_id.
-- Lock estimate: negligible (new empty table).
-- Re-run behavior: idempotent via IF NOT EXISTS.
-- Rollback: see bottom of file -- safe, this table starts empty.

create table if not exists openserp_query_rotation_state (
  query_id                 text primary key,
  query_universe_version   text not null,
  query_definition_hash    text not null,
  last_executed_at         timestamptz,
  next_eligible_at         timestamptz,
  failure_count            integer not null default 0,
  successful_run_count     integer not null default 0,
  discovery_yield          integer not null default 0,
  last_engine              text,
  last_run_id              text,
  created_at               timestamptz not null default now(),
  updated_at               timestamptz not null default now(),
  constraint openserp_query_rotation_state_failure_count_check check (failure_count >= 0),
  constraint openserp_query_rotation_state_success_count_check check (successful_run_count >= 0),
  constraint openserp_query_rotation_state_yield_check check (discovery_yield >= 0),
  constraint openserp_query_rotation_state_engine_check check (
    last_engine is null or last_engine in ('bing', 'duckduckgo', 'ecosia')
  )
);

alter table openserp_query_rotation_state enable row level security;
-- No anon/authenticated policy is created -- service_role only (BYPASSRLS), matching
-- the pattern already used by property_clusters/property_cluster_members/discovery_candidates.

create index if not exists openserp_query_rotation_state_next_eligible_idx
on openserp_query_rotation_state (next_eligible_at);

create index if not exists openserp_query_rotation_state_last_executed_idx
on openserp_query_rotation_state (last_executed_at);

-- ROLLBACK (manual, not auto-applied):
-- drop table if exists openserp_query_rotation_state;

-- OPENSERP-SERVERLESS-STATE-PERSISTENCE-1
-- Objective: replace the local-filesystem rewrite of data/openserp/engine-budget-state.json
--   (same EROFS failure mode as the query rotation state) with a PostgreSQL table
--   holding per-engine budget/backoff state. Must survive across serverless function
--   invocations, redeploys, and separate GitHub Actions runners -- a local file or
--   in-memory value cannot.
-- Preconditions: none (fresh, additive table).
-- Impact: creates 1 new table + index. No existing table touched. No PII, no raw
--   SERP data, no listing URLs stored here.
-- Lock estimate: negligible (new empty table).
-- Re-run behavior: idempotent via IF NOT EXISTS.
-- Rollback: see bottom of file -- safe, this table starts empty.

create table if not exists openserp_engine_budget_state (
  engine                 text primary key,
  state_version           text not null,
  current_budget          integer not null,
  consecutive_failures    integer not null default 0,
  captcha_count           integer not null default 0,
  rate_limit_count        integer not null default 0,
  timeout_count           integer not null default 0,
  suspended_until         timestamptz,
  last_success_at         timestamptz,
  last_failure_at         timestamptz,
  last_run_id             text,
  created_at              timestamptz not null default now(),
  updated_at              timestamptz not null default now(),
  constraint openserp_engine_budget_state_engine_check check (engine in ('bing', 'duckduckgo', 'ecosia')),
  constraint openserp_engine_budget_state_budget_range_check check (current_budget between 4 and 24),
  constraint openserp_engine_budget_state_consecutive_failures_check check (consecutive_failures >= 0),
  constraint openserp_engine_budget_state_captcha_count_check check (captcha_count >= 0),
  constraint openserp_engine_budget_state_rate_limit_count_check check (rate_limit_count >= 0),
  constraint openserp_engine_budget_state_timeout_count_check check (timeout_count >= 0)
);

alter table openserp_engine_budget_state enable row level security;
-- No anon/authenticated policy is created -- service_role only (BYPASSRLS), matching
-- the pattern already used by property_clusters/property_cluster_members/discovery_candidates.

create index if not exists openserp_engine_budget_state_suspended_until_idx
on openserp_engine_budget_state (suspended_until);

-- ROLLBACK (manual, not auto-applied):
-- drop table if exists openserp_engine_budget_state;

-- seed (begin/commit stripped -- part of this single outer transaction)
-- OPENSERP-SERVERLESS-STATE-PERSISTENCE-1 -- deterministic seed.
-- Generated by scripts/openserp/generate-serverless-state-seed.ts from the
-- static data/openserp/query-universe-v1.json catalog (universe_version:
-- openserp-query-universe-v1). Additive, idempotent (ON CONFLICT DO
-- NOTHING), transactional, no deletion, no listing table touched, no URL/
-- snippet/PII. created_at/updated_at intentionally omitted -- the tables'
-- own "default now()" applies at apply-time so this file's own content
-- (and hash) never depends on when it was generated or applied.


on conflict (query_id) do nothing;

on conflict (engine) do nothing;



-- verification block: raises (aborting the whole transaction) on any
-- mismatch versus the frozen expectations.
do $$
declare
  rotation_count integer;
  budget_count integer;
  distinct_query_ids integer;
  distinct_engines integer;
  policy_count integer;
begin
  select count(*) into rotation_count from openserp_query_rotation_state;
  if rotation_count <> 2718 then
    raise exception 'VERIFICATION FAILED: expected 2718 rotation rows, got %', rotation_count;
  end if;

  select count(*) into budget_count from openserp_engine_budget_state;
  if budget_count <> 3 then
    raise exception 'VERIFICATION FAILED: expected 3 budget rows, got %', budget_count;
  end if;

  select count(distinct query_id) into distinct_query_ids from openserp_query_rotation_state;
  if distinct_query_ids <> 2718 then
    raise exception 'VERIFICATION FAILED: expected 2718 distinct query_id, got %', distinct_query_ids;
  end if;

  select count(distinct engine) into distinct_engines from openserp_engine_budget_state;
  if distinct_engines <> 3 then
    raise exception 'VERIFICATION FAILED: expected 3 distinct engines, got %', distinct_engines;
  end if;

  select count(*) into policy_count from pg_policies where tablename in ('openserp_query_rotation_state', 'openserp_engine_budget_state');
  if policy_count <> 0 then
    raise exception 'VERIFICATION FAILED: expected 0 policies on the two new tables, got %', policy_count;
  end if;

  if not exists (select 1 from pg_class c join pg_namespace n on n.oid = c.relnamespace where n.nspname = 'public' and c.relname = 'openserp_query_rotation_state' and c.relrowsecurity) then
    raise exception 'VERIFICATION FAILED: RLS not enabled on openserp_query_rotation_state';
  end if;
  if not exists (select 1 from pg_class c join pg_namespace n on n.oid = c.relnamespace where n.nspname = 'public' and c.relname = 'openserp_engine_budget_state' and c.relrowsecurity) then
    raise exception 'VERIFICATION FAILED: RLS not enabled on openserp_engine_budget_state';
  end if;

  raise notice 'VERIFICATION PASSED: % rotation rows, % budget rows, RLS enabled on both, 0 policies', rotation_count, budget_count;
end $$;

commit;
